insert into catalogue_items (venue_id, category, name, description, price, price_unit, sort_order) values
('11111111-1111-1111-1111-111111111111', 'Glassware & Serveware', 'Champagne Flutes, Wine & Beer Glasses', '200× Champagne Flutes, Universal Wine glasses (red & white), Willy Beer glasses & Zombie glasses. Sufficient for all areas for up to 120 guests.', 0, 'fixed', 0),
('11111111-1111-1111-1111-111111111111', 'Glassware & Serveware', 'White Dinner Plates, Side Plates & Soup Bowls', '120× Marola broad-rim white catering crockery — formal wedding stock, all matching. Farmhouse Erika has its own informal crockery which does not match.', 0, 'fixed', 1),
('11111111-1111-1111-1111-111111111111', 'Glassware & Serveware', 'White Coffee / Tea Mugs', '70–100× Straight-sided catering mugs, no saucer. For Farewell Breakfast, late-night tea/coffee & hot chocolate station.', 0, 'fixed', 2),
('11111111-1111-1111-1111-111111111111', 'Glassware & Serveware', 'Dinner Cutlery & Salt & Pepper Shakers', '120× Dinner Knives, Forks, Dessert Spoons, Teaspoons & Cake Forks (Munich style stainless steel) — formal wedding cutlery. Plus 30 Salt & Pepper shaker sets.', 0, 'fixed', 3),
('11111111-1111-1111-1111-111111111111', 'Glassware & Serveware', 'Champagne Bowls & Ice Buckets (Large)', '2× XL ice buckets/bowls + 1× upright bucket. Large steel ice bowls — great for white wine, champagne, ice, beers & ciders.', 0, 'fixed', 4),
('11111111-1111-1111-1111-111111111111', 'Glassware & Serveware', 'Jugs, Carafes & Ashtrays', '15× variety of Water Jugs, Vintage Juice Jugs & Carafes — enough for all tables. Great for punch, water, juices & iced tea. Plus glass & ceramic ashtrays.', 0, 'fixed', 5),
('11111111-1111-1111-1111-111111111111', 'Glassware & Serveware', 'Ice Buckets — Stainless Steel (various)', 'Variety of SS ice buckets from large 5L with handles to smaller sizes. For ice on tables, at the bar, or chilling white wine & beers.', 0, 'fixed', 6),
('11111111-1111-1111-1111-111111111111', 'Glassware & Serveware', 'Sundry Bar & Wedding Cake Utensils', 'Ice tongs, waiters'' friends, serving spoons, wedding cake lifter & knife set. Catering-grade serving items for bar, harvest & buffet tables.', 0, 'fixed', 7),
('11111111-1111-1111-1111-111111111111', 'Glassware & Serveware', 'Wood Platters & Boards', '16× variety of Oak Barrel Head platters with rope handles, Oval Long Platters & Rectangular wood platters. Great for harvest table, cheese boards, pizzas & breads.', 0, 'fixed', 8),
('11111111-1111-1111-1111-111111111111', 'Décor & Display', 'Rustic Cake Stands & Fly Chasers', 'Wood tree-slice rustic cake stands on stands. Battery-operated swirling fly chasers for harvest table.', 0, 'fixed', 9),
('11111111-1111-1111-1111-111111111111', 'Kitchen & Braai', 'Cast-Iron Potjie Pots, Braai Grids & Utensils', '1× full set: Variety of No.3 to No.14 XXL cast-iron rounded potjie pots (small to HUGE), flat-bottomed pots, braai grids, braai tongs, braai spades, wooden spoons, etc. For M&G catering, potjie competitions & large-group braais.', 0, 'fixed', 10),
('11111111-1111-1111-1111-111111111111', 'Rustic Vessels', 'Galvanised Metal Rustic Buckets', '20+ galvanised metal buckets with handles — Small, Medium & Large. Weathered metal patina. Great as rustic ice buckets for drinks, or for flowers & confetti. Not for ice used in drinks.', 0, 'fixed', 11),
('11111111-1111-1111-1111-111111111111', 'Rustic Vessels', 'Half Oak Barrels — Round (with tub liners)', '5× half oak barrels cut across width, round. Includes tub liners to prevent leaking. For cooling "help-yourself" drinks stacked high with ice, flowers & décor, or turned over as coffee tables.', 0, 'fixed', 12),
('11111111-1111-1111-1111-111111111111', 'Rustic Vessels', 'Half Oak Barrel — Oval (with rope handles)', '2× half oak barrels cut lengthwise, oval-shaped with rope handles. Great for décor, flowers, confetti, umbrellas, breads, gifts, or transporting drinks.', 0, 'fixed', 13),
('11111111-1111-1111-1111-111111111111', 'Rustic Vessels', 'Wheel Barrows — Rustic & Patinaed', '2× rustic patinaed wheelbarrows. For transporting drinks or as rustic wedding décor — great for presenting mineral waters on ice at the ceremony or help-yourself iced beers & ciders.', 0, 'fixed', 14),
('11111111-1111-1111-1111-111111111111', 'Tables & Seating', 'Dinner Tables — Pine Whitewashed', '15× Pine whitewashed wedding tabletops (2.5m × 0.9m) on dark-stained trestle legs. For the reception dinner tables or elsewhere.', 0, 'fixed', 15),
('11111111-1111-1111-1111-111111111111', 'Tables & Seating', 'Kids Tables — Chalkboard Tabletops', '2× fun chalkboard tabletops for kids to eat at and draw on. Usually set up on straw bales — chalk supplied in a jar.', 0, 'fixed', 16),
('11111111-1111-1111-1111-111111111111', 'Tables & Seating', 'Pine White-Washed Ceremony Benches', '30× pine whitewashed ceremony benches with darker stained legs. For ceremony seating on level ground, seating at trestle tables, or around fire baskets & lounges.', 0, 'fixed', 17),
('11111111-1111-1111-1111-111111111111', 'Tables & Seating', 'Extra Tables — Slatted Pine (white)', '4× slatted pine tabletops (2.4m × 0.75m, white). For buffet tables, bar tops, harvest tables, display & décor, cake table, satellite bar, etc.', 0, 'fixed', 18),
('11111111-1111-1111-1111-111111111111', 'Tables & Seating', 'Harvest Tabletops — Extra Large', '2× very large harvest tabletops (3m × 1.2m) — one stained pine, one white. For harvest tables, buffet tables or bar tops. Usually set up on two oak barrels (bar height).', 0, 'fixed', 19),
('11111111-1111-1111-1111-111111111111', 'Tables & Seating', 'Extra Tables — Oregon Pine, Teak Square & Rectangular', '10× variety: Oregon Pine Square Tables (90×90cm), Teak Square café tables (90×90cm), Teak Rectangular Tables (150×95cm). For DJ, cake, décor, gifts, drinks station, coffee & tea setup, memory table, etc.', 0, 'fixed', 20),
('11111111-1111-1111-1111-111111111111', 'Tables & Seating', 'Rustic Coffee Tables from Reclaimed Pallet Wood', '5× rustic coffee tables (1m × 0.9m). For lounge pockets at pre-drinks, near fire baskets, or for lawn games.', 0, 'fixed', 21),
('11111111-1111-1111-1111-111111111111', 'Barrels & Crates', 'Oak Wine Barrels — Full Size', '10× full-size oak barrels (90cm high). For building bars, placing harvest tabletops on, general décor, ad-hoc tables, flowers, ceremony aisle ends, lawn games, etc.', 0, 'fixed', 22),
('11111111-1111-1111-1111-111111111111', 'Barrels & Crates', 'Harvest Bin / Pallet Apple Crates', '5× raw wood + 4× white-washed harvest bin crates. For building rustic satellite bars, harvest tables, or extending existing bars.', 0, 'fixed', 23),
('11111111-1111-1111-1111-111111111111', 'Soft Décor & Fabric', 'White Fabric Satin Draping — 7m', '1× long white satin draping for the oak tree, wrapped around the wedding arch, or ceremony use, etc.', 0, 'fixed', 24),
('11111111-1111-1111-1111-111111111111', 'Soft Décor & Fabric', 'White Flagged Bunting — approx 100m', '1× set of various triangular white flagged bunting pieces which can be joined. Creates a festive festival atmosphere, or cordons off areas.', 0, 'fixed', 25),
('11111111-1111-1111-1111-111111111111', 'Signage & Chalkboards', '"Cheers", "Mr & Mrs" Signs & Cutout Letters', '1× "Cheers" sign on board, 1× "Mr & Mrs" sign on board, plus larger "Mr" & "Mrs" cutout loose letters (approx 25cm high).', 0, 'fixed', 26),
('11111111-1111-1111-1111-111111111111', 'Rustic Vessels', 'Vintage Galvanised Watering Can & Milk Can', '1× large vintage galvanised watering can + 1× large galvanised milk can, both rustic patinaed metal. For general décor or flowers.', 0, 'fixed', 27),
('11111111-1111-1111-1111-111111111111', 'Signage & Chalkboards', 'Rustic Wood Step Ladder — Small', '1× small rustic wood step ladder with vintage patina. Great for displaying blankets & throws, seating plans, welcome drinks stand, cocktail display, or general décor.', 0, 'fixed', 28),
('11111111-1111-1111-1111-111111111111', 'Signage & Chalkboards', 'White-Washed Framed Chalkboard', '2× white-washed framed chalkboards (93×62cm board, 120×90cm with frame). For menus, seating plans, timeline, DJ lineup, cocktails, wedding poetry, etc.', 0, 'fixed', 29),
('11111111-1111-1111-1111-111111111111', 'Signage & Chalkboards', 'Rustic Pine Framed Chalkboard (Natural)', '1× rustic natural pine framed chalkboard (111×61cm board). For menus, seating plans, timeline, schedule, poetry, DJ lineup, cocktails, etc.', 0, 'fixed', 30),
('11111111-1111-1111-1111-111111111111', 'Frames, Easels & Mirrors', 'Painted Framed Mirrors — Large on Easel', '2× large painted framed mirrors, usually placed on easels wherever the Bride & Groom are getting ready. Also used as décor or signage.', 0, 'fixed', 31),
('11111111-1111-1111-1111-111111111111', 'Signage & Chalkboards', 'Ornate Gilded Framed Chalkboard', '1× beautiful ornately gilded framed chalkboard on stand (80×143cm). For menus, seating plans, quotes, etc. — chalk supplied. Perfect at the entrance to reception or ceremony.', 0, 'fixed', 32),
('11111111-1111-1111-1111-111111111111', 'Frames, Easels & Mirrors', 'Large Stained Wood "Photo" Frame', '1× large stained wood photo frame. Hung on poles at pre-drinks or reception — great for guests to pose behind, or to frame the mountain view.', 0, 'fixed', 33),
('11111111-1111-1111-1111-111111111111', 'Frames, Easels & Mirrors', 'Easels — Whitewashed Wood, Large Floorstanding', '4× large whitewashed wood floorstanding easels. For chalkboards, mirrors, seating plans, DJ line-ups, menus, schedule of events, etc.', 0, 'fixed', 34),
('11111111-1111-1111-1111-111111111111', 'Signage & Chalkboards', 'Smaller A4 Chalkboards in Wood Frame', '8× various A4-sized chalkboards in wood frames. For signage, menus, quirky one-liners, harvest table display, cocktail ingredients, etc.', 0, 'fixed', 35),
('11111111-1111-1111-1111-111111111111', 'Baskets & Rustic Décor', 'Sundry Wood Crates (Jonkeer, Coca Cola & Bashews)', '6× various wood crates. For décor, stacked display, storage & transport, flower or gift crates, or to build levels on the harvest table.', 0, 'fixed', 36),
('11111111-1111-1111-1111-111111111111', 'Baskets & Rustic Décor', 'Woven Cane & Harvest Baskets', '4× large & small woven baskets (round & square). For décor, flowers, confetti, cooldrinks, umbrellas, blankets, throws, breads, fruits, etc.', 0, 'fixed', 37),
('11111111-1111-1111-1111-111111111111', 'Baskets & Rustic Décor', 'Rustic Wooden Log Arch (180×200cm)', '1× rustic wooden log arch. Used at the ceremony area draped with cloth, macramé or flowers. Also as general décor or prop.', 0, 'fixed', 38),
('11111111-1111-1111-1111-111111111111', 'Baskets & Rustic Décor', 'Wood Branch Blocks — Name / Card Holders', '100× wood branch blocks with slot for names, menus, cocktail cards, etc. Bring your own cards to slide into the slot.', 0, 'fixed', 39),
('11111111-1111-1111-1111-111111111111', 'Signage & Chalkboards', 'Rustic Wooden Pallet Chalkboard', '1× rustic wooden pallet chalkboard for signage, directional info, menus, DJ lineup, Happy Hour, etc.', 0, 'fixed', 40),
('11111111-1111-1111-1111-111111111111', 'Baskets & Rustic Décor', 'Hearts — Chalkboard & Woven Twig Hearts', '2× white-washed heart-shaped chalkboard hearts, plain chalkboard hearts & woven hearts of twigs & branches. For signage or décor.', 0, 'fixed', 41),
('11111111-1111-1111-1111-111111111111', 'Baskets & Rustic Décor', 'Slender Metal Bird Cages — Black', '3× slender black metal bird cages. Hanging décor from trees or on tables — can hold tealight candles in the evening.', 0, 'fixed', 42),
('11111111-1111-1111-1111-111111111111', 'Frames, Easels & Mirrors', 'Tabletop Easels — Blackwood, Pine & White Metal', '5× variety of tabletop easels. For menus, cocktails, notices, seating plans, DJ info, or holding smaller framed chalkboards.', 0, 'fixed', 43),
('11111111-1111-1111-1111-111111111111', 'Signage & Chalkboards', 'Signage Stand Sets', '2× signage stands — one rustic trellis poles with chalkboard signs, one with neat printed signs on a wood stand. Directional & fun, to show guests where to go.', 0, 'fixed', 44);
