insert into accommodation_rooms (venue_id, name, room_type, sleeps, price_per_night, description, sort_order) values
('11111111-1111-1111-1111-111111111111', 'Oak Cottage', 'Bridal Suite', 2, 0, 'Open-plan cottage with double bed, slipper bath, air con, walk-in shower, fireplace, stoep & braai. Situated right next to the Barn Venue and Wedding Meadow — the natural choice as a Bridal Suite.
insert into suppliers (wedding_id, category, name, contact, cost, paid, notes) values
('22222222-2222-2222-2222-222222222222', 'Photography', 'Duane Smith Photography', '071 858 9653 · info@dsmith.co.za', 25000, false, 'Collection Two — Full Day Coverage. 9 hrs · 2 photographers · Wedding Timeline Assistance · On-site venue walkthrough · 1-week preview · 800+ edited HD images · Complimentary engagement shoot.'),
('22222222-2222-2222-2222-222222222222', 'Coordinator', 'Niki Events', 'Niki de Vries · 084 620 7703 · info@niki.events', NULL, false, 'Wedding Planning, Flowers & Décor. Based in Paarl.'),
('22222222-2222-2222-2222-222222222222', 'Coordinator', 'Ebb & Flow Events', 'Angela Millar · 082 310 6365 · info@ebbandflowevents.co.za', NULL, false, 'Flowers, Yoga & Event Management. LOCAL & ONSITE — based in Robertson.'),
